```typescript
import { Injectable, OnModuleInit, OnApplicationShutdown } from '@nestjs/common';

@Injectable()
export class DatabaseService implements OnModuleInit, OnApplicationShutdown {
  private isConnected = false;

  async onModuleInit() {
    console.log('Connexion à la base de données...');
    this.isConnected = true;
    console.log('Base de données connectée');
  }

  async onApplicationShutdown(signal?: string) {
    console.log(`Arrêt reçu (signal: ${signal}), fermeture de la connexion...`);
    this.isConnected = false;
    console.log('Connexion fermée');
  }
}
```

```typescript
import { Injectable, OnApplicationShutdown, Logger } from '@nestjs/common';

@Injectable()
export class OrderProcessor implements OnApplicationShutdown {
  private readonly logger = new Logger(OrderProcessor.name);
  private processingOrders = new Set<string>();
  private shutdownInProgress = false;

  async processOrder(orderId: string) {
    if (this.shutdownInProgress) {
      throw new Error('Arrêt en cours, impossible de traiter la commande');
    }
    this.processingOrders.add(orderId);
    try {
      // Simuler un traitement long
      await new Promise(resolve => setTimeout(resolve, 5000));
    } finally {
      this.processingOrders.delete(orderId);
    }
  }

  async onApplicationShutdown(signal: string) {
    this.logger.log(`Arrêt demandé (${signal}), attente des commandes en cours...`);
    this.shutdownInProgress = true;

    const timeout = 10000; // 10 secondes max
    const startTime = Date.now();

    while (this.processingOrders.size > 0 && (Date.now() - startTime) < timeout) {
      this.logger.log(`En attente de ${this.processingOrders.size} commande(s)...`);
      await new Promise(resolve => setTimeout(resolve, 500));
    }

    if (this.processingOrders.size > 0) {
      this.logger.warn(`Arrêt forcé, ${this.processingOrders.size} commande(s) non terminée(s)`);
    } else {
      this.logger.log('Toutes les commandes sont terminées, arrêt propre');
    }
  }
}
```

On peut créer un service `InitializationCoordinator` qui implémente `OnModuleInit`. Dans ce service, on injecte `DatabaseService` et `RedisService` (qui exposent leurs méthodes d'initialisation asynchrones). Puis :
```typescript
@Injectable()
export class InitializationCoordinator implements OnModuleInit {
  constructor(
    private dbService: DatabaseService,
    private redisService: RedisService,
  ) {}

  async onModuleInit() {
    await Promise.all([
      this.dbService.connect(),
      this.redisService.connect(),
    ]);
    console.log('Database et Redis initialisés en parallèle');
  }
}
```
On retire la logique d'init des hooks individuels pour éviter les duplications.

questions.texte:
Analysez ce code :
```typescript
@Injectable()
export class CacheService implements OnModuleInit {
  constructor(private configService: ConfigService) {}

  async onModuleInit() {
    console.log('Cache initialisé');
  }
}
```
Que se passe-t-il si `ConfigService` n'a pas encore fini son `OnModuleInit` (ex: chargement de .env) ? Proposez une correction avec `@Injectable({ eager: true })` ou une autre approche.

questions.reponse:
Deux solutions principales :
1) Utiliser `app.init()` avant `listen` pour forcer l'exécution complète des hooks d'initialisation :
```typescript
const app = await NestFactory.create(AppModule);
await app.init(); // attend tous les OnModuleInit
await app.listen(3000);
```
2) Implémenter un indicateur de readiness : dans DatabaseService, exposer une promesse `dbReady` et dans `bootstrap`, attendre cette promesse :
```typescript
const dbService = app.get(DatabaseService);
await dbService.waitForReady();
await app.listen(3000);
```
